const input = $input.first().json;
const skills = (input.tailored_resume.skills_matrix || []).slice(0,3).map(s => s.normalized).join(', ');
const prompt = `Generate outreach.\nTarget Role: ${input.job.title}\nTarget Company: ${input.job.company_name}\nTop 3 Skills: ${skills}`;

return [{
  json: {
    job_id: input.job.job_id || input.job.dedup_hash,
    prompt,
    model: $env.MODEL_OUTREACH || 'google/gemini-flash-1.5'
  }
}];

