const req = $('Build Prompt').item.json;
const llmRes = $input.first().json;

let outreach = {
  linkedin_message: '',
  email_draft: { subject: '', body: '' },
  follow_up_message: ''
};

try {
  if (llmRes.choices && llmRes.choices.length > 0) {
    const parsed = JSON.parse(llmRes.choices[0].message.content);
    outreach = { ...outreach, ...parsed };
  }
} catch (e) {}

return [{
  json: {
    job_id: req.job_id,
    outreach
  }
}];
